#!/usr/bin/env python3

import argparse
import sys

def count_file(filename):
    """Count lines, words, and characters in a file."""
    try:
        with open(filename, 'r') as f:
            lines = 0
            words = 0
            chars = 0
            for line in f:
                lines += 1
                words += len(line.split())
                chars += len(line)
            return lines, words, chars
    except FileNotFoundError:
        return None  # File not found
    except Exception:
        return None  # Other error

def count_stdin():
    """Count lines, words, and characters from stdin."""
    lines = 0
    words = 0
    chars = 0
    for line in sys.stdin:
        lines += 1
        words += len(line.split())
        chars += len(line)
    return lines, words, chars

def main():
    """Main function to parse arguments and process files."""
    parser = argparse.ArgumentParser(description='Count lines, words, and characters in files')
    parser.add_argument('files', metavar='FILE', nargs='*', help='Files to process')
    parser.add_argument('-l', '--lines', action='store_true', help='Count lines')
    parser.add_argument('-w', '--words', action='store_true', help='Count words')
    parser.add_argument('-c', '--chars', action='store_true', help='Count characters')

    args = parser.parse_args()

    # If no flags given, show all counts
    if not (args.lines or args.words or args.chars):
        args.lines = args.words = args.chars = True

    # Process files
    if not args.files:
        # Process stdin if no files given
        lines, words, chars = count_stdin()
        if args.lines and args.words and args.chars:
            print(f"{lines}\t{words}\t{chars}\tstdin")
        elif args.lines:
            print(f"{lines}\tstdin")
        elif args.words:
            print(f"{words}\tstdin")
        elif args.chars:
            print(f"{chars}\tstdin")
    else:
        total_lines = 0
        total_words = 0
        total_chars = 0
        all_files_valid = True

        for filename in args.files:
            counts = count_file(filename)
            if counts is None:
                print(f"wordcount.py: {filename}: No such file or directory", file=sys.stderr)
                all_files_valid = False
                continue

            lines, words, chars = counts
            if args.lines and args.words and args.chars:
                print(f"{lines}\t{words}\t{chars}\t{filename}")
            elif args.lines:
                print(f"{lines}\t{filename}")
            elif args.words:
                print(f"{words}\t{filename}")
            elif args.chars:
                print(f"{chars}\t{filename}")

            # Accumulate totals
            total_lines += lines
            total_words += words
            total_chars += chars

        # Print total line if multiple files
        if len(args.files) > 1:
            if args.lines and args.words and args.chars:
                print(f"{total_lines}\t{total_words}\t{total_chars}\ttotal")
            elif args.lines:
                print(f"{total_lines}\ttotal")
            elif args.words:
                print(f"{total_words}\ttotal")
            elif args.chars:
                print(f"{total_chars}\ttotal")

        # Exit with error code 1 if any file not found
        if not all_files_valid:
            sys.exit(1)

if __name__ == "__main__":
    main()
